final:
module RefModule(
   input                clk ,
   input                rst_n,

   output reg [3:0]     Q  
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or negedge rst_n or posedge dbg_halt)begin
        if(!rst_n) Q <= 4'd0;
        else if(Q == 4'd9) Q <= 4'd0;
        else Q <= Q + 4'd1;
    end
endmodule
